select teacher_id, teacher_no, teacher_name, gender
from teacher


        and (
            teacher_no like concat('%', #{keyword}, '%')
            or teacher_name like concat('%', #{keyword}, '%')
        )


        and gender = #{gender}


order by teacher_id
limit #{pageSize} offset #{offset}

select count(*) from teacher
and ( teacher_no like concat('%', #{keyword}, '%') or teacher_name like concat('%', #{keyword}, '%') )
and gender = #{gender}

select teacher_id, teacher_no, teacher_name, gender
from teacher
where teacher_id = #{teacherId}

